// ============================================================================
// NANO BANANA PRO - PROMPT ENHANCER (V4)
// Extraction robuste du prompt depuis diverses sources
// ============================================================================

const input = $input.first().json;

// Fonction pour extraire le prompt de manière robuste
function extractPrompt(data) {
    // 1. Format Creative V6: query.some_input
    if (data.query && data.query.some_input) {
        return data.query.some_input;
    }
    // 2. Direct fields
    if (data.some_input) return data.some_input;
    if (data.positive_prompt) return data.positive_prompt;
    if (data.prompt) return data.prompt;
    if (data.chatInput) return data.chatInput;
    if (data.message) return data.message;
    if (data.text) return data.text;

    // 3. Nested query fields
    if (data.query) {
        if (data.query.prompt) return data.query.prompt;
        if (data.query.positive_prompt) return data.query.positive_prompt;
        if (data.query.chatInput) return data.query.chatInput;
    }

    return null;
}

const userPrompt = extractPrompt(input) || 'Modern minimalist marketing visual';
const aspectRatio = input.aspect_ratio || input.query?.aspect_ratio || '1:1';
const style = input.style || input.query?.style || 'minimalist, tech, premium';
const brandColors = input.brand_colors || input.query?.brand_colors || '#000000, #FFFFFF, #FF00FF, #00FFFF';

// Determiner la taille
let size = '1024x1024';
if (aspectRatio === '9:16' || aspectRatio === '9/16') {
  size = '1024x1792';
} else if (aspectRatio === '16:9' || aspectRatio === '16/9') {
  size = '1792x1024';
}

// Enrichir le prompt
const enhancedPrompt = `${userPrompt}

STYLE REQUIREMENTS:
- Ultra high quality, 8K resolution
- ${style}
- Color palette: ${brandColors}
- Dark background (black or deep slate)
- Neon accents and glow effects
- Clean composition with 30% negative space
- Professional marketing aesthetic
- NO text, NO watermarks, NO logos
- Photorealistic lighting with dramatic shadows`;

return [{
  json: {
    enhanced_prompt: enhancedPrompt,
    original_prompt: userPrompt,
    size: size,
    aspect_ratio: aspectRatio,
    style: style
  }
}];

// ============================================================================
// NANO BANANA PRO - OUTPUT FORMATTER (V3 - GEMINI + IMGBB)
// Pour Gemini image generation avec upload imgbb
// ============================================================================

const imgbbResponse = $input.first().json;
let enhancerData = {};
let imageUrl = null;
let uploadSuccess = false;
let errorMessage = '';

// Recuperer les donnees du node Enhance Prompt
try {
  enhancerData = $('Enhance Prompt').first().json;
} catch (e) {
  enhancerData = { enhanced_prompt: '', original_prompt: '', size: '1024x1024' };
}

// Extraire l'URL de imgbb
// imgbb retourne: { success: true, data: { display_url: "...", url: "..." } }
try {
    if (imgbbResponse && imgbbResponse.success === true && imgbbResponse.data) {
        imageUrl = imgbbResponse.data.display_url || imgbbResponse.data.url;
        uploadSuccess = true;
    } else if (imgbbResponse && imgbbResponse.error) {
        errorMessage = imgbbResponse.error.message || JSON.stringify(imgbbResponse.error);
    }
} catch (e) {
    errorMessage = 'Erreur parsing imgbb: ' + e.message;
}

if (!imageUrl) {
  return [{
    json: {
      success: false,
      tool: 'nano_banana_pro',
      error: errorMessage || 'Upload failed: ' + JSON.stringify(imgbbResponse),
      image: null,
      image_url: null,
      generated_at: new Date().toISOString()
    }
  }];
}

// Structure de sortie pour l'Agent Principal
return [{
  json: {
    success: true,
    tool: 'nano_banana_pro',
    image: {
      url: imageUrl,
      prompt_used: enhancerData.enhanced_prompt || '',
      original_prompt: enhancerData.original_prompt || '',
      size: enhancerData.size || '1024x1024',
      aspect_ratio: enhancerData.aspect_ratio || '1:1',
      style: enhancerData.style || 'minimalist, tech, premium',
      model: 'gemini-2.0-flash-exp-image-generation',
      quality: 'hd'
    },
    // IMPORTANT: image_url au niveau racine pour l'extraction frontend
    image_url: imageUrl,
    prompt_used: enhancerData.original_prompt || '',
    provider: 'imgbb',
    generated_at: new Date().toISOString()
  }
}];

// ============================================================================
// ERROR HANDLER - Format error response
// ============================================================================

const error = $input.first().json;

return [{
  json: {
    success: false,
    tool: 'nano_banana_pro',
    error: {
      message: error.message || 'Image generation failed',
      details: JSON.stringify(error)
    },
    image: null,
    image_url: null,
    generated_at: new Date().toISOString()
  }
}];
